#include <stdio.h>
#include <string.h>

int parse_command(const char *raw, char *out, size_t out_sz) {
    char temp[256];  /* line 10: static array - not inherently unsafe */

    /* Extract command after 'CMD:' prefix */
    const char *prefix = strstr(raw, "CMD:");
    if (!prefix) return -1;
    prefix += 4;

    /* line 18: SAFE - strncpy bounded by sizeof(temp) */
    strncpy(temp, prefix, sizeof(temp) - 1);
    temp[sizeof(temp) - 1] = '\0';

    /* Copy to output - bounded by out_sz */
    strncpy(out, temp, out_sz - 1);
    out[out_sz - 1] = '\0';
    return 0;
}

